window.__QUIZ_DATA__=[{"id":"theory>Geography>2004>SECTION A>1>a","subject":"Geography","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline four factors wich promotes international trade between your country and the outside world","images":[],"marking_scheme":"-Differences in resources and natural endowment are factors that necessitate the trade   -Demand for commodities that we cannot produce necessitates the trade   -Some crops are more suited to certain climatic conditions,for example cocoa and cotton grow well under tropical condition,while crops like wheat,barley and oats grow in temperate climate of the world.  -Differences in technical knowledge is another reason for the trade.Some trade like Germany,Japan,Britain,USA etc have higher technical knowledge than some countries in West Africa.  -Some tariffs and import duties charge on goods are also some of the factors  -Favourable government policy always promote the trade  -In international trade,reliable transport and communication network are vital to the trade.  -Stable government promotes international trade.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2004>SECTION A>1>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Explain three problems involed in the trade between your country and other west African countries.","images":[],"marking_scheme":"-There is Inadequate capital to fund International trade.  -Difference in language militate against the success of the trade  -Similarities of products pose a lot of problem.Many countries produce similar goods  -Low level of technology may hamper active participation in the trade.  -Unfavourable balance of trade due to differences in growth levels impedes the trade.  -Low level of savings because of poverty may impact on the growth of the trade.  -High cost of production of oods, due to unfavourable climate always affects the trade  -Poor transportation system in most countries not good enough for the trade  -Unstable political situation kills investment and trade relationships  -Attachment to colonial masters does not help the participation of former colonial states in the trade.","marks":"5","difficulty":"3"},{"id":"theory>Geography>2004>SECTION A>1>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Suggest three solution to the problems explained in 1(b) above","images":[],"marking_scheme":"-There should be improved specialisation in production.This will lead to improved technology which will lead to improvement in both the quality and quantity in goods exported.  -There should be improved technology which will lead to improvement in both the quality and quantity in goods by export  -More patronage of locally made goods by other countries must be encouraged through initiative and policies.  -There should be protection from competition   -Improved savings capacity will improve the trade  -Construction of trans-continental transport network since transport is the live-wire of the trade.  -Through its policies,government should embark on trade liberalisation  -There should be efficient management of the ports  -Regional co-operation and integration should be encouraged.  -Political stability is a pre-requisite for the growth of the trade.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION A>2>a","subject":"Geography","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"In what five ways has railway transport contributed to economic development in tropical Africa","images":[],"marking_scheme":"-It encourages national integration   -It has contributed to movement of people and goods which has in turn hastened economic growth.  -The industrial areas are linked together by rail  -It makes possible movement of bulky goods at cheaper rates from one area to another.  -It promotes Inter-regional trade and co-operation  -It creates employment for a teeming number of people","marks":"10","difficulty":"2"},{"id":"theory>Geography>2004>SECTION A>2>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Suggest five ways of improving the developmet of railway transport int tropical Africa","images":[],"marking_scheme":"-Deliberate effort should be made towards the expension of the rail network. This will generate growth in the economy.  -Effort geared towards improvement of the efficiencyof the rail network, should be undertaken   -Government should make capital available to railway, this will enhance efficiency.  -Training and retaining of personnel should be undertaken from time to time.  -There should be regular maintenance of rail facilities e.g track,coaches,engines. This will increase efficiency.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2004>SECTION A>3>a","subject":"Geography","year":"2004","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight three human and three physical factors which may favour a rapid growth of population","images":[],"marking_scheme":"HUMAN FACTORS  -Improved agricultural practices will increase the level of productivity, thus leading to rapid population growth.  -Some religion like islam encourages polygamy which leads to procreation of more children.  -Highly industrialised society breeds rapid growth in population  -Improved social amenities,like pipeborne water,electricity e.t.c favour rapid population growth.  -If most people migrate to a country, there will be rapid population growth.  -Improved transportation can lead to rapid population  -Improved social facilities e.g efficient healthcare can guarantee growth in population  PHYSICAL FACTORS  -A favourable climate for agricultural.This leads to increase in productivity  -Availability of water can guarantee growth in population especially in the arid region of the world.  -Availability of water can also lead to growth in population.  -Availability of good soil can attract population settlement  -The presence of minerals can lead to more people coming in to boost the mining community and for other related activities.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2004>SECTION A>3>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"State four problems that may arise from rapid population growth","images":[],"marking_scheme":"-High rate of infant motality is a certainty in a growing population because of social pressure   -High mobility will also ensure in a rapid growing population  -Rapid population growth is always accompanied by food shortages  -There would be high birth rate which eventually lead to over crowding  -The pressure on the lean social service may lead to low life expectancy  -Inadequate social amenities will not be able to accomodate the population  -The available housing will not be enough for the growing population  -As a result of the rapid population, there will be too much pressure on facilities.  -Overpopulation always breeds vices such as armed robbery,prostitution etc  -Over crowding:Growing population always leads to overcrowding.  -Inadequate transport facilities is a logical outgrowth of growing population.  -Inflation is bound to occur, In a situation of growin population.  -Malnutrition and disease:This will lead to diseases, because of the pressure on resource and facilities  -High dependency ratio:This is always a logical outgrowth of growing population.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2004>SECTION B>4>a>i","subject":"Geography","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Draw an outline map of nigeria , on the  map show and name    two international airports","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"8","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>4>a>ii","subject":"Geography","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Draw an outline map of nigeria , on the  map show and name   The railway line between lagos and minna","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>4>a>iii","subject":"Geography","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Draw an outline map of nigeria , on the  map show and name   One major inland waterway","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>4>a>iv","subject":"Geography","year":"2004","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Draw an outline map of nigeria , on the  map show and name   one seaport and riverport","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>4>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"In what four ways is road transport of economic importance to nigeria","images":[],"marking_scheme":"-Road transportation has improved movement of goods and passangers from one place to another   -Information and services are passed through road transportation  -It has improved domestic trade   -It is a source of employment to a teeming number of people  -Diffusion of ideas and innovation are enhanced through road transport  -It opens up the interior for further development   -It provides international links for business, politics, and commerce e.t.c  -It is important for export and import of goods and services across boarders.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2004>SECTION B>4>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TRANSPORTATION","question":"Highlight two problems of road transport in Nigeria","images":[],"marking_scheme":"-Poor condition of road is one of the problem facing road transportation in Nigeria  -Lack of maintenance culture creates problem  -Cost of maintenance of roads which involves large sum of money after road transportation is another problem.  -Most vehicle are not property maintained. Others are rickety and old.  -Spare parts are costly, and this has hampered the business of maintenance of vehicles.  -Petrol and diesel are costly and this always affects transportation.  -Transport in our society is costly and expensive.  -Most roads are not motorable in rainy season.","marks":"2","difficulty":"2"},{"id":"theory>Geography>2004>SECTION B>5>a>i","subject":"Geography","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Draw an outlinne map of Nigeria. on the map, show and name    one area noted for the mining of any three of the following crude oil, columbite , iron ore","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>5>a>ii","subject":"Geography","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Draw an outlinne map of Nigeria. on the map, show and name  one major town in any three of the areas shown in 5(ai) above","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>5>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"outline five ways in which crude oil contributes to the economic development of nigeria","images":[],"marking_scheme":"-It acts as a source of foreign exchange to the government and the nation.  -It is also a source of income to workers in the oil industries or sub-sectors of the economy  -It as well provides employment opportunities for the people.  -It leads to the growth of towns and the development of cosmopolitan areas   -It makes essential goods available   -It makes possible specialisation and skills acquisition.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION B>6>a>i","subject":"Geography","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria .on the map locate    one area eachfor the production of cocoa , palm produced, groundnut and cotton","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2004>SECTION B>6>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight three maor problems of agriculture in Nigeria","images":[],"marking_scheme":"-Changes in climatic condition affect agriculture   -Some soil is arid and may not be good enough for agriculture   -Pests and diseases destroy farmland and crops  -Some of our storage facilities are sub-standard.  -Many who are supposed to farm,leave rural areas for urban centres  -Shortage of fund hampers the development of agriculture   -Our people are largely illiterate about farm techniques   -The problem of transport to convey farm product is real and formidable.  -The problem of land tenure often affect agriculture  -Prices often fluctuate and these always affect agriculture","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION B>6>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"suggest solution to the problems highlighted in 6(b)above","images":[],"marking_scheme":"-There should be extensive development of irrigation in arid areas and land reclamation undertaken in swampy region areas   -Soil quality can be improved by the proper application of manure or fertilizer  -Application of insecticides, fungicides and spraying or dusting with chemicals will solve the problems of pests and disease  -There should be development of modern of preservation e.g giant tanks for grains(silos) refrigerators. for slaughtered cattle.  -There should be a change in the quality of rural life by providing basic infrastructures in rural areas.  -Soft loan should be provided for farmers e.g cooperatives to farmers.  -There should be land reform programme e.g Merging of several farm lands will ease the difficulties.  -There should be improvement on the level of education through different training programmes.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>7>a>i","subject":"Geography","year":"2004","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Name two areas of copper mining in zambia","images":[],"marking_scheme":"Area of Copper mining in Zambia are  -Ndola  -Nchanga  -Chibuluma  -Baucroft","marks":"5","difficulty":"1"},{"id":"theory>Geography>2004>SECTION C>7>a>ii","subject":"Geography","year":"2004","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe one method of copper mining","images":[],"marking_scheme":"Methods of copper mining are:  -Open cast method:The top soil will be removed by mechanical shovels. Thereafter, water will be used to wash sand ore. Then,the ore wil be carried to concentrators that will filter the copper.  -Deep Cast or Shaft method:There would be digging of vertical holes that would reach the ore bearing rocks. These holes are filled with explosive to shatter the rocks and the broken are brought to the surface. After this the rocks are taken to concentrators that filter the copper.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>7>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight four contribution of copper miing to the econmic  developmet of zambia","images":[],"marking_scheme":"-It is a source of foreign exchange   -It creates employment opportunities for the zambian people  -It provides raw materials for industries e.g metallurgical indutries  -It makes available the provision of electrical equipment.  -The availability of good alloys is as a result of copper mining  -It generates revenue to government of zambia  -It also generates revenue for the miners  -It helps the people to acquire skills  -The presence of copper mining hastens infrastructural development  -Development of towns and urban centres is hastened by copper minning","marks":"5","difficulty":"3"},{"id":"theory>Geography>2004>SECTION C>7>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"What three problems faces the mining of copper in zambia?","images":[],"marking_scheme":"-There is inadequate capital  -Transport network is poor and inadequate   -Some of the workers are often not skilled   -The fluctuation in price in the world market affect it  -The mines are at times,poorly managed   -Conflicts between the local people and the prospecting companies and labour unrest affect the production","marks":"5","difficulty":"3"},{"id":"theory>Geography>2004>SECTION C>8>a>i","subject":"Geography","year":"2004","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Draw a sketch map of africa, on the map locate and name:    Two ecowas countries aong the coast","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>8>a>ii","subject":"Geography","year":"2004","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Draw a sketch map of africa, on the map locate and name:    two ecowas coutries in the interior","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>8>a>iii","subject":"Geography","year":"2004","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of africa, on the map locate and name:    The capitals of any three of the countries in 8(ai)","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"4","difficulty":"3"},{"id":"theory>Geography>2004>SECTION C>8>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Highlight three problems acing the economic  cooperation of west African states","images":[],"marking_scheme":"-There is problem of poor transportation and communication  -Fear of domination by weaker members affects co-operation.  -Currency differencies pose a lot of problem  -Language barrier is also a problem  -Political instability of member countries affect the free flow of trade and investments.  -Attachment to former colonial masters creates dependency syndrome on the part of some states.  -Some of the countries produces similar products","marks":"4","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>8>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"suggest a solution to the problems in 8(b) above","images":[],"marking_scheme":"-Improvement of transport and communication network   -Adoption of a common currency will ease the problem of difference in curriencies  -Member countries should ensure political stability by good governance  -There should be encouragement of common languages  -There should be diversification of crop production.  -Members should detach themselves from their former colonial masters  -Members should be committed in all their activities.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>9>a","subject":"Geography","year":"2004","type":"Theory","sub_label":"a","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Dra a sketch map of Africa, on the map,locate and name two areas important for lumbering","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2004>SECTION C>9>b","subject":"Geography","year":"2004","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline four factors that promote lumbering in Africa","images":[],"marking_scheme":"-Availability of trees promotes lumbering to a large extent   -Good climate is favourable to the development of lumbering  -Fertile soil influences forest growth.  -Establishment of sawmills enhance lumbering.  -High demand for wood leads to lumbering  -Improved transportation system creates access to forest and enhances lumbering.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2004>SECTION C>9>c","subject":"Geography","year":"2004","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : SELECTED TOPICS","question":"Highligt three benefits of lumbering in Africa","images":[],"marking_scheme":"-It acts as a source of foreign exchange to the continent.  -It provides employment opportunities to the people  -It provides revenue to government  -It also provides income to workers  -It provides raw materials for industries and firms   -It provides wood for carved and other artworks  -It provides wood for construction and allied services.","marks":"5","difficulty":"1"}];